{
var seed = GetInt(parameters, "seed", context.Seed);
var capType = GetChoice(parameters, "capType", "dome");
var size = GetFloat(parameters, "size", 0.5f);
var capRatio = GetFloat(parameters, "capRatio", 0.6f);
var capColor = GetColor(parameters, "capColor", Color.FromRgb(200, 60, 60));
var capHL = GetColor(parameters, "capHighlight", Color.FromRgb(240, 120, 100));
var stemColor = GetColor(parameters, "stemColor", Color.FromRgb(220, 200, 180));
var spots = GetBool(parameters, "spots", true);

var tileSize = context.TileSize;
var buffer = new PixelBuffer(tileSize, tileSize);

var cR = capColor.R / 255f; var cG = capColor.G / 255f; var cB = capColor.B / 255f;
var hR = capHL.R / 255f; var hG = capHL.G / 255f; var hB = capHL.B / 255f;
var sR = stemColor.R / 255f; var sG = stemColor.G / 255f; var sB = stemColor.B / 255f;

var halfSize = tileSize * 0.5f;
var totalHeight = halfSize * size;
var capHeight = totalHeight * capRatio;
var stemHeight = totalHeight - capHeight;
var stemWidth = totalHeight * 0.2f;

buffer.ParallelForEachPixel((x, y) =>
{
    var px = x + 0.5f - halfSize;
    var py = y + 0.5f - halfSize;

    // Coordinate system: mushroom centered, stem at bottom
    var capCenterY = -stemHeight;
    var stemBottom = capCenterY + stemHeight;
    var stemTop = capCenterY;

    // Is this pixel in the stem region?
    var inStem = false;
    var inCap = false;
    var stemAlpha = 0f;
    var capAlpha = 0f;

    // Stem: vertical rectangle with rounded bottom
    if (py >= stemTop && py <= stemBottom)
    {
        var stemLocalX = MathF.Abs(px);
        var stemEdge = stemWidth * (1f - (py - stemTop) / stemHeight * 0.3f);
        if (stemLocalX < stemEdge)
        {
            stemAlpha = 1f;
            inStem = true;
        }
        else
        {
            var edgeDist = (stemLocalX - stemEdge) / (stemWidth * 0.2f);
            stemAlpha = Math.Clamp(1f - edgeDist, 0f, 1f);
            if (stemAlpha > 0.01f) inStem = true;
        }
    }

    // Cap: shaped based on type
    if (py <= capCenterY)
    {
        var capLocalY = (capCenterY - py) / capHeight; // 0 at bottom, 1 at top
        if (capLocalY >= 0f && capLocalY <= 1.2f)
        {
            var capWidth = totalHeight * 0.7f * (1f - capLocalY * 0.7f);

            // Cap shape profile
            var profile = capType switch
            {
                "conical" => capLocalY,
                "trumpet" => MathF.Sqrt(capLocalY) * 0.5f + 0.5f,
                "flat" => 0.2f + capLocalY * 0.1f,
                _ => 1f - (1f - capLocalY) * (1f - capLocalY) // dome: rounded
            };
            capWidth *= profile * 1.5f;

            var capLocalX = MathF.Abs(px);
            if (capLocalX < capWidth)
            {
                capAlpha = 1f;
                inCap = true;
            }
            else
            {
                var edgeDist = (capLocalX - capWidth) / (totalHeight * 0.1f);
                capAlpha = Math.Clamp(1f - edgeDist, 0f, 1f);
                if (capAlpha > 0.01f) inCap = true;
            }
        }
    }

    if (!inStem && !inCap)
    {
        buffer.SetPixel(x, y, 0, 0, 0, 0);
        return;
    }

    // Color mixing for stem
    if (inStem && (!inCap || capAlpha < stemAlpha))
    {
        var shadow = 1f - (py - stemTop) / stemHeight * 0.3f;
        var colorVar = HashToUnit((int)(px * 10), (int)(py * 10), seed + 50) * 0.05f;
        buffer.SetPixel(x, y,
            Math.Clamp(sR * shadow + colorVar, 0f, 1f),
            Math.Clamp(sG * shadow + colorVar, 0f, 1f),
            Math.Clamp(sB * shadow + colorVar, 0f, 1f),
            stemAlpha);
        return;
    }

    // Cap coloring
    if (inCap)
    {
        var capLocalY = (capCenterY - py) / capHeight;
        // Lighting: top-left highlights
        var light = (1f - px / (totalHeight * 0.5f)) * 0.3f + (1f - capLocalY) * 0.3f;
        light = Math.Clamp(light + 0.3f, 0f, 1f);

        float fr, fg, fb;
        if (light < 0.5f)
        {
            var lt = light * 2f;
            fr = Lerp(cR * 0.6f, cR, lt);
            fg = Lerp(cG * 0.6f, cG, lt);
            fb = Lerp(cB * 0.6f, cB, lt);
        }
        else
        {
            var lt = (light - 0.5f) * 2f;
            fr = Lerp(cR, hR, lt);
            fg = Lerp(cG, hG, lt);
            fb = Lerp(cB, hB, lt);
        }

        // Spots on cap
        if (spots)
        {
            var spotSeed = seed + 100;
            var spotX = (int)((px + halfSize) / tileSize * 8 + 0.5f);
            var spotY = (int)((py + halfSize) / tileSize * 8 + 0.5f);
            var hasSpot = HashToUnit(spotX, spotY, spotSeed) > 0.7f;
            if (hasSpot && capLocalY > 0.2f && MathF.Abs(px) > stemWidth * 0.5f)
            {
                // White/cream spot
                fr = Lerp(fr, 1f, 0.7f);
                fg = Lerp(fg, 0.95f, 0.7f);
                fb = Lerp(fb, 0.85f, 0.7f);
            }
        }

        buffer.SetPixel(x, y,
            Math.Clamp(fr, 0f, 1f),
            Math.Clamp(fg, 0f, 1f),
            Math.Clamp(fb, 0f, 1f), capAlpha);
        return;
    }

    buffer.SetPixel(x, y, 0, 0, 0, 0);
});

return buffer;
}
